public class FileSort {
    public String[] solution(String[] files) {
        Pattern p = Pattern.compile("^([^0-9]+)(\\d{1,5})(.*)");
        Arrays.sort(files, (a, b) -> {
            Matcher ma = p.matcher(a), mb = p.matcher(b);
            ma.find(); mb.find();
            int headCmp = ma.group(1).toLowerCase().compareTo(mb.group(1).toLowerCase());
            if (headCmp != 0) return headCmp;
            return Integer.compare(Integer.parseInt(ma.group(2)), Integer.parseInt(mb.group(2)));
        });
        return files;
    }
}

