public class Friends4Block {
    public int solution(int m, int n, String[] board) {
        char[][] grid = new char[m][n];
        for (int i = 0; i < m; i++) grid[i] = board[i].toCharArray();
        int total = 0;
        while (true) {
            boolean[][] toRemove = new boolean[m][n];
            for (int r = 0; r < m-1; r++)
                for (int c = 0; c < n-1; c++) {
                    char ch = grid[r][c];
                    if (ch != '.' && ch == grid[r][c+1] && ch == grid[r+1][c] && ch == grid[r+1][c+1])
                        toRemove[r][c] = toRemove[r][c+1] = toRemove[r+1][c] = toRemove[r+1][c+1] = true;
                }
            int removed = 0;
            for (int r = 0; r < m; r++)
                for (int c = 0; c < n; c++)
                    if (toRemove[r][c]) { grid[r][c] = '.'; removed++; }
            if (removed == 0) break;
            total += removed;
            for (int c = 0; c < n; c++) {
                int bottom = m - 1;
                for (int r = m-1; r >= 0; r--)
                    if (grid[r][c] != '.') grid[bottom--][c] = grid[r][c];
                while (bottom >= 0) grid[bottom--][c] = '.';
            }
        }
        return total;
    }
}

public class LIS {
    public int lengthOfLIS(int[] nums) {
        int[] tails = new int[nums.length];
        int size = 0;
        for (int num : nums) {
            int lo = 0, hi = size;
            while (lo < hi) {
                int mid = (lo + hi) / 2;
                if (tails[mid] < num) lo = mid + 1;
                else hi = mid;
            }
            tails[lo] = num;
            if (lo == size) size++;
        }
        return size;
    }
}

public class EditDistance {
    public int minDistance(String word1, String word2) {
        int m = word1.length(), n = word2.length();
        int[][] dp = new int[m+1][n+1];
        for (int i = 0; i <= m; i++) dp[i][0] = i;
        for (int j = 0; j <= n; j++) dp[0][j] = j;
        for (int i = 1; i <= m; i++)
            for (int j = 1; j <= n; j++)
                if (word1.charAt(i-1) == word2.charAt(j-1))
                    dp[i][j] = dp[i-1][j-1];
                else
                    dp[i][j] = 1 + Math.min(dp[i-1][j-1], Math.min(dp[i-1][j], dp[i][j-1]));
        return dp[m][n];
    }
}

