public class TopologicalSort {
    public int solution(int n, int[][] relations) {
        List<Integer>[] graph = new ArrayList[n+1];
        int[] indegree = new int[n+1], dist = new int[n+1];
        for (int i = 1; i <= n; i++) graph[i] = new ArrayList<>();
        for (int[] r : relations) { graph[r[0]].add(r[1]); indegree[r[1]]++; }

        Queue<Integer> q = new ArrayDeque<>();
        for (int i = 1; i <= n; i++)
            if (indegree[i] == 0) { q.offer(i); dist[i] = 1; }

        while (!q.isEmpty()) {
            int cur = q.poll();
            for (int next : graph[cur]) {
                dist[next] = Math.max(dist[next], dist[cur] + 1);
                if (--indegree[next] == 0) q.offer(next);
            }
        }

        int ans = 0;
        for (int i = 1; i <= n; i++) ans = Math.max(ans, dist[i]);
        return ans;
    }
}

