public class DeliveryStats {
    public double[] solution(long[][] logs) {
        Map<Long, Map<String, Long>> orderEvents = new HashMap<>();
        String[] types = {"CREATED", "SHIPPED", "DELIVERED"};
        for (long[] log : logs) {
            long orderId = log[0];
            String eventType = types[(int)log[1]];
            orderEvents.computeIfAbsent(orderId, k -> new HashMap<>()).put(eventType, log[2]);
        }

        List<Long> deliveryTimes = new ArrayList<>();
        for (Map<String, Long> events : orderEvents.values()) {
            if (events.containsKey("CREATED") && events.containsKey("DELIVERED"))
                deliveryTimes.add(events.get("DELIVERED") - events.get("CREATED"));
        }

        if (deliveryTimes.isEmpty()) return new double[]{0, 0, 0};
        long sum = 0, max = Long.MIN_VALUE, min = Long.MAX_VALUE;
        for (long t : deliveryTimes) { sum += t; max = Math.max(max, t); min = Math.min(min, t); }
        return new double[]{(double)sum/deliveryTimes.size(), max, min};
    }
}

