public class InventoryManager {
    public List<Integer> solution(String[][] queries) {
        // {price, insertOrder, quantity}
        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) ->
            a[0] != b[0] ? Long.compare(a[0], b[0]) : Long.compare(a[1], b[1]));
        long order = 0;
        List<Integer> result = new ArrayList<>();

        for (String[] q : queries) {
            switch (q[0]) {
                case "ADD" -> pq.offer(new long[]{Long.parseLong(q[3]), order++, Long.parseLong(q[2])});
                case "SELL" -> {
                    long remaining = Long.parseLong(q[2]);
                    while (!pq.isEmpty() && remaining > 0) {
                        long[] top = pq.poll();
                        if (top[2] <= remaining) { remaining -= top[2]; }
                        else { top[2] -= remaining; remaining = 0; pq.offer(top); }
                    }
                }
                case "MIN_PRICE" -> result.add(pq.isEmpty() ? -1 : (int) pq.peek()[0]);
            }
        }
        return result;
    }
}

