public class LogAnalysis {
    public String solution(int[][] requests, int windowSize) {
        Arrays.sort(requests, (a, b) -> a[0] - b[0]);
        Map<Integer, Integer> cnt = new HashMap<>();
        int left = 0, maxCnt = 0, bestUser = -1;

        for (int right = 0; right < requests.length; right++) {
            int uid = requests[right][1];
            cnt.merge(uid, 1, Integer::sum);

            while (requests[right][0] - requests[left][0] >= windowSize) {
                int lu = requests[left][1];
                cnt.merge(lu, -1, Integer::sum);
                if (cnt.get(lu) == 0) cnt.remove(lu);
                left++;
            }

            int c = cnt.get(uid);
            if (c > maxCnt || (c == maxCnt && (bestUser == -1 || uid < bestUser))) {
                maxCnt = c; bestUser = uid;
            }
        }
        return String.valueOf(bestUser);
    }
}

