public class PriceChange {
    public int[] solution(int[] prices) {
        int n = prices.length;
        int[] result = new int[n];
        Deque<Integer> stack = new ArrayDeque<>(); // 인덱스 저장

        for (int i = 0; i < n; i++) {
            // 현재 가격이 스택 top의 가격보다 낮으면 가격 하락
            while (!stack.isEmpty() && prices[stack.peek()] > prices[i]) {
                int idx = stack.pop();
                result[idx] = i - idx; // 유지 시간
            }
            stack.push(i);
        }

        // 스택에 남은 인덱스: 끝까지 하락 없음
        while (!stack.isEmpty()) {
            int idx = stack.pop();
            result[idx] = n - 1 - idx;
        }
        return result;
    }
}

