public class ProductScore {
    private static final Map<String, Integer> SCORE = Map.of("VIEW", 1, "CART", 3, "PURCHASE", 5);

    public List<String> solution(String[][] logs, int k) {
        Map<String, Integer> scores = new HashMap<>();
        for (String[] log : logs)
            scores.merge(log[1], SCORE.get(log[2]), Integer::sum);

        return scores.entrySet().stream()
            .sorted((a, b) -> !a.getValue().equals(b.getValue())
                ? b.getValue() - a.getValue()
                : a.getKey().compareTo(b.getKey()))
            .limit(k)
            .map(Map.Entry::getKey)
            .collect(java.util.stream.Collectors.toList());
    }
}

