public class DeadlockDetection {
    private static final int UNVISITED = 0, VISITING = 1, VISITED = 2;

    public List<List<Integer>> solution(int[][] transfers) {
        Map<Integer, List<Integer>> graph = new HashMap<>();
        Set<Integer> nodes = new HashSet<>();
        for (int[] t : transfers) {
            graph.computeIfAbsent(t[0], k -> new ArrayList<>()).add(t[1]);
            nodes.add(t[0]); nodes.add(t[1]);
        }

        Map<Integer, Integer> state = new HashMap<>();
        for (int n : nodes) state.put(n, UNVISITED);
        List<List<Integer>> cycles = new ArrayList<>();
        Deque<Integer> path = new ArrayDeque<>();

        for (int node : nodes)
            if (state.get(node) == UNVISITED)
                dfs(node, graph, state, path, cycles);

        cycles.forEach(Collections::sort);
        return cycles;
    }

    private void dfs(int node, Map<Integer, List<Integer>> graph,
                     Map<Integer, Integer> state, Deque<Integer> path, List<List<Integer>> cycles) {
        state.put(node, VISITING);
        path.push(node);
        for (int next : graph.getOrDefault(node, Collections.emptyList())) {
            if (state.get(next) == UNVISITED) {
                dfs(next, graph, state, path, cycles);
            } else if (state.get(next) == VISITING) {
                // 사이클 발견: path에서 next부터 현재까지 추출
                List<Integer> cycle = new ArrayList<>();
                Iterator<Integer> it = path.iterator();
                while (it.hasNext()) {
                    int n = it.next();
                    cycle.add(n);
                    if (n == next) break;
                }
                cycles.add(cycle);
            }
        }
        path.pop();
        state.put(node, VISITED);
    }
}

