public class TransactionOrder {
    public Map<Integer, Long> solution(long[][] events) {
        // events: [accountId, txId, timestamp, type(0=DEBIT/1=CREDIT), amount]
        Map<Integer, List<long[]>> grouped = new HashMap<>();
        for (long[] e : events)
            grouped.computeIfAbsent((int)e[0], k -> new ArrayList<>()).add(e);

        Map<Integer, Long> balances = new HashMap<>();
        for (Map.Entry<Integer, List<long[]>> entry : grouped.entrySet()) {
            int accountId = entry.getKey();
            List<long[]> txs = entry.getValue();
            txs.sort(Comparator.comparingLong(a -> a[2])); // timestamp 정렬

            long balance = 0;
            for (long[] tx : txs) {
                long amount = tx[4];
                if (tx[3] == 1) { // CREDIT
                    balance += amount;
                } else { // DEBIT
                    if (balance >= amount) balance -= amount; // 부족 시 무효
                }
            }
            balances.put(accountId, balance);
        }
        return balances;
    }
}

