public class BalanceRollback {
    public long solution(String[][] logs) {
        long balance = 0;
        Deque<Long> savepoints = new ArrayDeque<>();

        for (String[] log : logs) {
            String type = log[1];
            long amount = Long.parseLong(log[2]);
            switch (type) {
                case "BEGIN" -> savepoints.push(balance); // savepoint 저장
                case "DEPOSIT" -> balance += amount;
                case "WITHDRAW" -> balance -= amount;
                case "COMMIT" -> savepoints.pop(); // 확정: savepoint 제거
                case "ROLLBACK" -> balance = savepoints.pop(); // 복원
            }
        }
        return balance;
    }
}

import java.math.BigDecimal;
import java.math.RoundingMode;

public class FeeCalculation {
    public long[] solution(long[] transactions, double[][] feeRates) {
        long[] result = new long[transactions.length];
        for (int i = 0; i < transactions.length; i++) {
            long amount = transactions[i];
            BigDecimal fee = BigDecimal.ZERO;
            for (int j = 0; j < feeRates.length; j++) {
                long lower = (long) feeRates[j][0];
                long upper = j + 1 < feeRates.length ? (long) feeRates[j+1][0] : Long.MAX_VALUE;
                BigDecimal rate = BigDecimal.valueOf(feeRates[j][1]).divide(BigDecimal.valueOf(100));
                if (amount > lower) {
                    long taxable = Math.min(amount, upper) - lower;
                    fee = fee.add(BigDecimal.valueOf(taxable).multiply(rate));
                }
            }
            result[i] = fee.setScale(0, RoundingMode.FLOOR).longValue();
        }
        return result;
    }
}

