public class FraudDetection {
    public List<String> solution(long[][] logs, int maxTxCount, int timeWindow) {
        // logs: [userId, amount, timestamp, merchantId] (모두 long/int로 인코딩)
        Map<Long, List<long[]>> userLogs = new HashMap<>();
        for (long[] log : logs)
            userLogs.computeIfAbsent(log[0], k -> new ArrayList<>()).add(log);

        Set<String> suspects = new HashSet<>();
        for (Map.Entry<Long, List<long[]>> entry : userLogs.entrySet()) {
            List<long[]> txs = entry.getValue();
            txs.sort(Comparator.comparingLong(a -> a[2]));

            int left = 0;
            Set<Long> merchants = new LinkedHashSet<>();
            for (int right = 0; right < txs.size(); right++) {
                merchants.add(txs.get(right)[3]);
                while (txs.get(right)[2] - txs.get(left)[2] >= timeWindow) {
                    merchants.remove(txs.get(left)[3]); // 이탈 merchant 제거 시 주의!
                    left++;
                }
                int windowSize = right - left + 1;
                if (windowSize > maxTxCount || merchants.size() > 1)
                    suspects.add(String.valueOf(entry.getKey()));
            }
        }
        List<String> result = new ArrayList<>(suspects);
        Collections.sort(result);
        return result;
    }
}

