public class DeliveryRoute {
    private int[] startPos;
    private int[][] locations;
    private double minDist = Double.MAX_VALUE;

    public double solution(int[] start, int[][] locations) {
        this.startPos = start;
        this.locations = locations;
        int n = locations.length;
        int[] indices = new int[n];
        for (int i = 0; i < n; i++) indices[i] = i;
        permute(indices, 0);
        return Math.round(minDist * 1000.0) / 1000.0;
    }

    private void permute(int[] arr, int start) {
        if (start == arr.length) {
            double dist = distance(startPos[0], startPos[1], locations[arr[0]][0], locations[arr[0]][1]);
            for (int i = 0; i < arr.length - 1; i++)
                dist += distance(locations[arr[i]][0], locations[arr[i]][1],
                                  locations[arr[i+1]][0], locations[arr[i+1]][1]);
            minDist = Math.min(minDist, dist);
            return;
        }
        for (int i = start; i < arr.length; i++) {
            int tmp = arr[start]; arr[start] = arr[i]; arr[i] = tmp;
            permute(arr, start + 1);
            tmp = arr[start]; arr[start] = arr[i]; arr[i] = tmp;
        }
    }

    private double distance(int x1, int y1, int x2, int y2) {
        return Math.sqrt((double)(x2-x1)*(x2-x1) + (double)(y2-y1)*(y2-y1));
    }
}

