public class UsedMarketMatch {
    public List<long[]> solution(long[][] posts, Object[] query) {
        String targetCategory = (String) query[0];
        long maxPrice = (long) query[1];
        double qLat = (double) query[2], qLng = (double) query[3];
        double radiusKm = (double) query[4];
        int withinDays = (int) query[5];
        long now = System.currentTimeMillis() / 86400000L; // 현재 일수 (예시)

        List<long[]> result = new ArrayList<>();
        for (long[] post : posts) {
            // post: [postId, category(hash), price, lat*1e6, lng*1e6, createdDayAgo]
            if (!categoryMatch(post[1], targetCategory)) continue;
            if (post[2] > maxPrice) continue;
            if (post[5] > withinDays) continue;
            double distKm = haversineApprox(qLat, qLng, post[3] / 1e6, post[4] / 1e6);
            if (distKm > radiusKm) continue;
            result.add(post);
        }
        result.sort(Comparator.comparingLong(a -> a[2]));
        return result;
    }

    private double haversineApprox(double lat1, double lng1, double lat2, double lng2) {
        double dlat = (lat2 - lat1) * 111.0;
        double dlng = (lng2 - lng1) * 111.0 * Math.cos(Math.toRadians((lat1+lat2)/2));
        return Math.sqrt(dlat*dlat + dlng*dlng);
    }

    private boolean categoryMatch(long encoded, String category) {
        return String.valueOf(encoded).equals(category); // 실제로는 적절히 구현
    }
}

