public class OrderStateMachine {
    private static final Map<String, Set<String>> TRANSITIONS = new HashMap<>();
    static {
        TRANSITIONS.put("PENDING", Set.of("CONFIRMED", "CANCELLED"));
        TRANSITIONS.put("CONFIRMED", Set.of("COOKING", "CANCELLED"));
        TRANSITIONS.put("COOKING", Set.of("READY", "CANCELLED"));
        TRANSITIONS.put("READY", Set.of("DELIVERING", "CANCELLED"));
        TRANSITIONS.put("DELIVERING", Set.of("DELIVERED", "CANCELLED"));
        TRANSITIONS.put("DELIVERED", Set.of());
        TRANSITIONS.put("CANCELLED", Set.of());
    }

    public Map<String, String> solution(String[][] events) {
        Map<String, String> orderStates = new HashMap<>();

        for (String[] event : events) {
            String orderId = event[0], newState = event[1];
            String currentState = orderStates.get(orderId);

            if (currentState == null) {
                // 최초 이벤트는 PENDING만 허용
                if (newState.equals("PENDING")) orderStates.put(orderId, "PENDING");
            } else {
                Set<String> validNext = TRANSITIONS.getOrDefault(currentState, Set.of());
                if (validNext.contains(newState)) orderStates.put(orderId, newState);
                // 유효하지 않은 전환은 무시
            }
        }
        return orderStates;
    }
}

