public class WeightedAdDistribution {
    public Map<String, Integer> solution(int[][] ads, String[] adIds, int n, long seed) {
        int k = ads.length;
        int[] cumWeights = new int[k];
        cumWeights[0] = ads[0][0];
        for (int i = 1; i < k; i++) cumWeights[i] = cumWeights[i-1] + ads[i][0];
        int totalWeight = cumWeights[k-1];

        Map<String, Integer> result = new HashMap<>();
        for (String id : adIds) result.put(id, 0);

        Random rnd = new Random(seed);
        for (int i = 0; i < n; i++) {
            int r = rnd.nextInt(totalWeight); // [0, totalWeight)
            // upper bound: r < cumWeights[idx] 인 첫 번째 idx
            int lo = 0, hi = k - 1;
            while (lo < hi) {
                int mid = (lo + hi) / 2;
                if (cumWeights[mid] <= r) lo = mid + 1;
                else hi = mid;
            }
            result.merge(adIds[lo], 1, Integer::sum);
        }
        return result;
    }
}

