    public List<long[]> solution(long[][] messages, int windowSec, int maxCount) {
        // messages: [userId, messageId, timestamp]
        Map<Long, Deque<Long>> userQueues = new HashMap<>(); // userId -> 발송 시각 deque
        List<long[]> result = new ArrayList<>();

        for (long[] msg : messages) {
            long userId = msg[0], msgId = msg[1], requestTime = msg[2];
            Deque<Long> queue = userQueues.computeIfAbsent(userId, k -> new ArrayDeque<>());

            // windowSec 이전 발송 시각 제거
            long sendTime = requestTime;
            // 만약 queue가 가득 차 있으면 지연
            while (!queue.isEmpty() && queue.peekFirst() + windowSec <= sendTime) {
                queue.pollFirst();
            }

            if (queue.size() >= maxCount) {
                // 다음 가능한 시점: 가장 오래된 발송 시각 + windowSec
                sendTime = queue.peekFirst() + windowSec;
                // 지연된 sendTime 기준으로 다시 만료된 항목 제거
                while (queue.size() >= maxCount && queue.peekFirst() + windowSec <= sendTime) {
                    queue.pollFirst();
                }
            }

            queue.addLast(sendTime);
            result.add(new long[]{msgId, sendTime});
        }

        result.sort(Comparator.comparingLong(a -> a[1]));
        return result;
    }
}
